def calc_odds():
    a_sum = int(rclient.get('race.a.money'))
    b_sum = int(rclient.get('race.b.money'))
    if a_sum == 0:
        a_sum = 1
    if b_sum == 0:
        b_sum = 1

    a_odds = a_sum / float(b_sum)
    b_odds = b_sum / float(a_sum)

    return a_odds, b_odds, a_sum, b_sum

